#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define dbg(x) cerr<<#x" = "<<(x)<<'\n';
const int N=10005;
int n,m,b,f[N],vis[N],ans[N];
struct node
{
	int u;
	ll w;
	bool operator<(const node other)  const
	{
		return w>other.w;
	}
};
priority_queue<node> pq;
struct Node
{
	int v,w,num;
};
vector<Node> g[N];
bool dij(ll mid)
{
	memset(vis,0,sizeof(vis));
	memset(ans,0x3f,sizeof(ans));
	while(!pq.empty()) pq.pop();
	ans[1]=0;
	pq.push(node{1,0});
	while(!pq.empty())
	{
		node t=pq.top();
		pq.pop();
		int u=t.u;
		ll w=t.w;
		if(vis[u]) continue;
		vis[u]=1;
		for(int i=0;i<g[u].size();i++)
		{
			Node tt=g[u][i];
			int v=tt.v,ww=tt.w,num=tt.num;
			if(ww>mid) continue;
			if(!vis[v]&&ans[u]+num<ans[v])
			{
				ans[v]=ans[u]+num;
				pq.push(node{v,ans[v]});
			}
		}
	}
//	cout<<mid<<"  "<<ans[n]<<"\n";
	if(ans[n]<=b) return 1;
	return 0;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m>>b;
	for(int i=1;i<=n;i++)
	{
		cin>>f[i];
	}
	for(int i=1;i<=m;i++)
	{
		int a,bb,c;
		cin>>a>>bb>>c;
		g[a].push_back(Node{bb,f[bb],c});
		g[bb].push_back(Node{a,f[a],c});
	}
	ll l=f[1],r=1e9,mid;
	while(l<=r)
	{
		mid=(l+r)/2;
		if(dij(mid))
		{
			r=mid-1;
		}
		else l=mid+1;
	}
	if(r==1e9) cout<<"AFK";
	else cout<<r+1;
	return 0;
}
